/**
 * SPARQL defines {@code eval(Join(P1,P2)) = Join(eval(P1), eval(P2))} and
 * {@code eval(LeftJoin(P1,P2,F)) = LeftJoin(eval(P1), eval(P2), F)}: each operand denotes one independently evaluated
 * solution multiset. A physical strategy may rescan or push bindings into an operand only when the observable outcome
 * is one the algebra permits. For an OPTIONAL (or nested group) whose pattern is {@code BIND(UUID() AS ?u)}, the
 * operand's single evaluation contains one fresh UUID, which is then joined with every left solution — so all result
 * rows share the same {@code ?u}. A per-left-row re-evaluation observably deviates: each UUID() call must return a
 * different value, so distinct {@code ?u} values per row cannot arise from any single evaluation of the operand. The
 * bare {@code BIND} control differs: there the Extend node's input already contains one mapping per row, so per-row
 * fresh values are required.
 */
public class MemoryIndependentOperandSemanticsTest {

	private SailRepository repository;

	@BeforeEach
	public void setUp() {
		repository = new SailRepository(new MemoryStore());
		repository.init();
	}

	@AfterEach
	public void tearDown() {
		repository.shutDown();
	}

	private List<BindingSet> evaluate(String query) {
		try (RepositoryConnection connection = repository.getConnection()) {
			return QueryResults.asList(connection.prepareTupleQuery(query).evaluate());
		}
	}

	private static Set<Value> distinctValues(List<BindingSet> rows, String name) {
		Set<Value> values = new HashSet<>();
		for (BindingSet row : rows) {
			values.add(row.getValue(name));
		}
		return values;
	}

	@Test
	public void uuidInOptionalIsSharedAcrossLeftRows() {
		List<BindingSet> rows = evaluate(
				"SELECT ?x ?u WHERE { VALUES ?x { 1 2 } OPTIONAL { BIND(UUID() AS ?u) } }");

		assertEquals(2, rows.size());
		assertEquals(1, distinctValues(rows, "u").size(),
				"the OPTIONAL operand is evaluated independently once; its single fresh UUID joins with every left row");
	}

	@Test
	public void uuidInNestedGroupIsSharedAcrossLeftRows() {
		List<BindingSet> rows = evaluate(
				"SELECT ?x ?u WHERE { VALUES ?x { 1 2 } { BIND(UUID() AS ?u) } }");

		assertEquals(2, rows.size());
		assertEquals(1, distinctValues(rows, "u").size(),
				"the nested group operand is evaluated independently once");
	}

	@Test
	public void uuidInSameScopeIsFreshPerRow() {
		List<BindingSet> rows = evaluate(
				"SELECT ?x ?u WHERE { VALUES ?x { 1 2 } BIND(UUID() AS ?u) }");

		assertEquals(2, rows.size());
		assertEquals(2, distinctValues(rows, "u").size(),
				"the Extend node's input contains one mapping per row; each UUID() call returns a different value");
	}

	@Test
	public void struuidInOptionalIsSharedAcrossLeftRows() {
		List<BindingSet> rows = evaluate(
				"SELECT ?x ?u WHERE { VALUES ?x { 1 2 } OPTIONAL { BIND(STRUUID() AS ?u) } }");

		assertEquals(2, rows.size());
		assertEquals(1, distinctValues(rows, "u").size());
	}

	@Test
	public void bnodeInOptionalIsSharedAcrossLeftRows() {
		List<BindingSet> rows = evaluate(
				"SELECT ?x ?b WHERE { VALUES ?x { 1 2 } OPTIONAL { BIND(BNODE() AS ?b) } }");

		assertEquals(2, rows.size());
		assertEquals(1, distinctValues(rows, "b").size(),
				"the OPTIONAL operand's single evaluation contains one fresh blank node");
	}

	@Test
	public void bnodeInSameScopeIsFreshPerRow() {
		List<BindingSet> rows = evaluate(
				"SELECT ?x ?b WHERE { VALUES ?x { 1 2 } BIND(BNODE() AS ?b) }");

		assertEquals(2, rows.size());
		assertEquals(2, distinctValues(rows, "b").size());
	}

	/**
	 * Both projection expressions are evaluated over the same solution mapping, so BNODE("k") must map the shared label
	 * to one blank node per row and to distinct blank nodes across rows. Chained
	 * {@code BIND(BNODE("k") ...) BIND(BNODE("k") ...)} is deliberately NOT asserted: each BIND's Extend produces a
	 * successive (extended) mapping, and SPARQL does not settle whether those count as "one solution mapping" for
	 * BNODE's label scope.
	 */
	@Test
	public void bnodeWithArgumentIsMappingLocal() {
		List<BindingSet> rows = evaluate(
				"SELECT ?x (BNODE(\"k\") AS ?b1) (BNODE(\"k\") AS ?b2) WHERE { VALUES ?x { 1 2 } }");

		assertEquals(2, rows.size());
		for (BindingSet row : rows) {
			assertEquals(row.getValue("b1"), row.getValue("b2"),
					"BNODE(\"k\") maps the same label to the same blank node within one solution mapping");
		}
		assertNotEquals(rows.get(0).getValue("b1"), rows.get(1).getValue("b1"),
				"BNODE(\"k\") produces distinct blank nodes for distinct solution mappings");
	}
}
